// Filter supported document files (PDF + Images) and merge with config
const config = $('Config (API Keys)').item.json;
const triggerItems = $('OneDrive Trigger').all();
const supportedExtensions = ['.pdf', '.jpg', '.jpeg', '.png', '.bmp', '.tiff'];

const items = triggerItems.filter(item => {
  const name = (item.json.name || '').toLowerCase();
  return supportedExtensions.some(ext => name.endsWith(ext));
});

if (items.length === 0) {
  throw new Error('No supported files found (PDF, JPG, PNG, BMP, TIFF)');
}

return items.map(item => ({ 
  json: { 
    ...item.json, 
    _config: config,
    _fileType: (item.json.name || '').toLowerCase().endsWith('.pdf') ? 'pdf' : 'image'
  } 
}));

// Prepare blob path and upload metadata
const config = $('Config (API Keys)').item.json;
const originalFileName = $input.item.binary?.data?.fileName || $json.name || 'document';
const fileType = $('Filter Documents (PDF + Images)').item.json._fileType;
const now = new Date();

const ext = originalFileName.toLowerCase().split('.').pop();
const timestamp = now.getTime().toString(36);
const safeFileName = originalFileName.replace(/[^a-zA-Z0-9._-]/g, '_').slice(0, 100) || `doc_${timestamp}.${ext}`;
const fileName = originalFileName;

const blobFolder = `${now.getFullYear()}/${String(now.getMonth() + 1).padStart(2, '0')}`;
const blobPath = `${blobFolder}/${safeFileName}`;
const encodedBlobPath = `${blobFolder}/${encodeURIComponent(safeFileName)}`;

const safeBinary = JSON.parse(JSON.stringify($input.item.binary || {}));
if (safeBinary.data && safeBinary.data.fileName) {
  safeBinary.data.fileName = safeFileName;
}

const contentTypes = {
  'pdf': 'application/pdf',
  'jpg': 'image/jpeg',
  'jpeg': 'image/jpeg',
  'png': 'image/png',
  'bmp': 'image/bmp',
  'tiff': 'image/tiff'
};
const contentType = contentTypes[ext] || 'application/octet-stream';

return { 
  json: { 
    fileName, 
    blobFolder, 
    blobPath, 
    encodedBlobPath, 
    fileType,
    contentType,
    _config: config 
  }, 
  binary: safeBinary 
};

const config = $('Prepare Upload').item.json._config;
const meta = $('Prepare Upload').item.json;
const operationUrl = $('Submit OCR').item.json.headers['operation-location'];
const sleep = (ms) => new Promise(resolve => setTimeout(resolve, ms));

// n8n Cloud has 60s limit - use 15 attempts x 3s = 45s max
for (let attempt = 0; attempt < 15; attempt++) {
  await sleep(3000);
  const result = await this.helpers.httpRequest({ 
    method: 'GET', 
    url: operationUrl, 
    headers: { 'Ocp-Apim-Subscription-Key': config.AZURE_DOC_INTEL_KEY }, 
    json: true 
  });
  if (result.status === 'succeeded') {
    return { json: { ...result, _config: config, _meta: meta } };
  }
  if (result.status === 'failed') {
    throw new Error('OCR failed: ' + JSON.stringify(result.error));
  }
}
throw new Error('OCR timeout - document may be too large for Cloud processing');

const config = $json._config;
const meta = $json._meta;
const ocr = $json.analyzeResult || {};
const text = ocr.content || '';
const pages = ocr.pages || [];

const pageSpans = [];
let offset = 0;
for (let i = 0; i < pages.length; i++) {
  const len = pages[i].spans?.reduce((s, sp) => s + (sp.length || 0), 0) || 0;
  pageSpans.push({ pageNumber: i + 1, start: offset, end: offset + len });
  offset += len;
}

const tables = (ocr.tables || []).map((t, idx) => {
  const rows = {};
  for (const cell of (t.cells || [])) { 
    if (!rows[cell.rowIndex]) rows[cell.rowIndex] = []; 
    rows[cell.rowIndex][cell.columnIndex] = cell.content || ''; 
  }
  const content = Object.keys(rows).sort((a,b) => a-b).map(r => rows[r].filter(c => c !== undefined).join(' | ')).join('\n');
  return { content, pageNumber: t.boundingRegions?.[0]?.pageNumber || 1 };
});

const figures = [];
for (let i = 0; i < (ocr.figures || []).length; i++) {
  const fig = ocr.figures[i];
  const caption = fig.caption?.content || '';
  const pageNumber = fig.boundingRegions?.[0]?.pageNumber || 1;
  if (caption) figures.push({ caption, pageNumber });
}

return { 
  json: { 
    text, 
    pageSpans, 
    tables, 
    figures, 
    fileName: meta.fileName, 
    blobPath: meta.blobPath, 
    encodedBlobPath: meta.encodedBlobPath,
    fileType: meta.fileType,
    stats: { 
      textLength: text.length, 
      pageCount: pages.length, 
      tableCount: tables.length, 
      figureCount: figures.length 
    }, 
    _config: config 
  } 
};

// AI Classification: Determine if document is LISTING, LISTING_LIST, NEWS, or CONTACT
const data = $json;
const config = data._config;
const tableContent = data.tables.map((t, i) => `[Table ${i+1}]:\n${t.content}`).join('\n\n');

const textStart = data.text.slice(0, 4000);
const textEnd = data.text.slice(-2000);
const fullContent = (textStart + '\n...\n' + textEnd + '\n\n' + tableContent).slice(0, 8000);

const classifyPrompt = `Analyze this Hong Kong property document and classify it.

Document: ${data.fileName}
File Type: ${data.fileType}
Page Count: ${data.stats.pageCount}
Text Length: ${data.stats.textLength} characters
Table Count: ${data.stats.tableCount}

Content (start and end of document):
${fullContent}

---
Classify as ONE of:

1. LISTING_LIST - Multi-property listing document (IMPORTANT - check this first):
   - Contains MULTIPLE numbered property entries (1), 2), 3)... or 1. 2. 3...)
   - Table format with repeated rows for different properties
   - Multiple 樓盤編號 (property IDs) in the document
   - Broker listing sheets with many properties
   - Keywords: 旺舖出租精選, 物業列表, 精選推介
   - Usually has columns: 地址, 面積, 租金, etc. for EACH property
   - More than 3 distinct properties in the document

2. LISTING - Single property for rent/sale:
   - ONE specific property only
   - Has asking rent or sale price for ONE property
   - Agent contact info
   - Keywords: 招租, 出售, For Lease, For Sale, Subject to Contract
   - Property particulars with area, floor, unit details
   - Leasing proposal, sales brochure, tenancy terms

3. NEWS - Market news, transaction report, or media article:
   - Completed transaction (成交, 售出, transaction)
   - News source, newspaper section
   - Reporter/journalist byline
   - Historical prices, profit/loss analysis

4. CONTACT - Business card or contact information:
   - Person's name prominently displayed
   - Job title / position
   - Company name
   - Phone numbers, mobile, email address
   - Usually a single page/image with minimal text
   - NO property details, NO asking rent

IMPORTANT: If you see multiple properties in a table format with different addresses and prices, classify as LISTING_LIST, not LISTING.

Return ONLY valid JSON:
{"classification": "listing" or "listing_list" or "news" or "contact", "confidence": 0.0-1.0, "reasoning": "Brief explanation", "propertyCount": number or null}`;

const response = await this.helpers.httpRequest({
  method: 'POST',
  url: 'https://openrouter.ai/api/v1/chat/completions',
  headers: {
    'Authorization': 'Bearer ' + config.OPENROUTER_API_KEY,
    'Content-Type': 'application/json'
  },
  body: {
    model: 'meta-llama/llama-3.3-70b-instruct',
    messages: [
      { role: 'system', content: 'You are a Hong Kong property document classifier. Return only valid JSON. Pay special attention to multi-property listing documents.' },
      { role: 'user', content: classifyPrompt }
    ],
    temperature: 0.1
  },
  json: true
});

let classification = { classification: 'listing', confidence: 0.5, propertyCount: 1 };
try {
  let content = response.choices[0].message.content;
  content = content.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  const jsonMatch = content.match(/\{[\s\S]*\}/);
  if (jsonMatch) classification = JSON.parse(jsonMatch[0]);
} catch (e) {
  classification.error = e.message;
}

// Auto-detect listing_list if multiple tables with property data
if (data.stats.tableCount >= 2 && data.stats.pageCount >= 2 && classification.classification === 'listing') {
  // Check if tables look like property listings
  const allTableContent = data.tables.map(t => t.content).join(' ').toLowerCase();
  const hasMultiplePropertyIndicators =
    (allTableContent.match(/樓盤編號/g) || []).length >= 3 ||
    (allTableContent.match(/vacant|已吉|現吉/gi) || []).length >= 3 ||
    (allTableContent.match(/\d{2,3},\d{3}/g) || []).length >= 5;  // Multiple rent amounts

  if (hasMultiplePropertyIndicators) {
    classification.classification = 'listing_list';
    classification.confidence = 0.85;
    classification.reasoning = 'Auto-detected as listing_list: multiple property entries in tables';
  }
}

// Auto-detect contact if image file with short text
if (data.fileType === 'image' && data.stats.textLength < 500 && data.stats.pageCount === 1) {
  const textLower = data.text.toLowerCase();
  const hasContactIndicators =
    (textLower.includes('@') || textLower.includes('email')) &&
    (textLower.includes('mobile') || textLower.includes('tel') || /\+?\d{2,3}[\s-]?\d{4}[\s-]?\d{4}/.test(data.text));

  if (hasContactIndicators && classification.classification !== 'contact') {
    classification.classification = 'contact';
    classification.confidence = 0.85;
    classification.reasoning = 'Auto-detected as contact: image file with email/phone pattern';
  }
}

return {
  json: {
    ...data,
    classification: classification.classification || 'listing',
    classificationConfidence: classification.confidence || 0.5,
    classificationReasoning: classification.reasoning || '',
    estimatedPropertyCount: classification.propertyCount || 1
  }
};

// Prepare extraction prompt for LISTING documents
const data = $json;
const tableContent = data.tables.map((t, i) => `[Table ${i+1}]:\n${t.content}`).join('\n\n');

const textStart = data.text.slice(0, 6000);
const textEnd = data.text.slice(-4000);
const fullContent = (textStart + '\n...\n' + textEnd + '\n\n' + tableContent).slice(0, 12000);

return {
  json: {
    ...data,
    extractionPrompt: `Document: ${data.fileName}\n\nContent:\n${fullContent}`
  }
};

const aiOutput = $('AI Listing Extractor').item.json.output || $('AI Listing Extractor').item.json.text || '{}';
const originalData = $('Prepare Listing Prompt').item.json;

let propertyData = {};
try {
  let rawContent = aiOutput;
  rawContent = rawContent.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  const jsonMatch = rawContent.match(/\{[\s\S]*\}/);
  if (jsonMatch) rawContent = jsonMatch[0];
  propertyData = JSON.parse(rawContent);
} catch (e) {
  propertyData = { error: e.message, rawResponse: aiOutput.slice(0, 500) };
}

return {
  json: {
    text: originalData.text,
    pageSpans: originalData.pageSpans,
    tables: originalData.tables,
    figures: originalData.figures,
    fileName: originalData.fileName,
    blobPath: originalData.blobPath,
    encodedBlobPath: originalData.encodedBlobPath,
    fileType: originalData.fileType,
    stats: originalData.stats,
    classification: 'listing',
    _config: originalData._config,
    propertyData
  }
};

const data = $json;
const config = data._config;
const prop = data.propertyData || {};
const CHUNK_SIZE = 600;
const OVERLAP = 150;

const keyTopics = [];
if (prop.building_name) keyTopics.push(prop.building_name);
if (prop.name_cn) keyTopics.push(prop.name_cn);
if (prop.district) keyTopics.push(prop.district);
if (prop.property_type) keyTopics.push(prop.property_type);

const validDistricts = ['central','admiralty','wan_chai','causeway_bay','north_point','quarry_bay','taikoo','wong_chuk_hang','sheung_wan','sai_ying_pun','kennedy_town','happy_valley','tin_hau','fortress_hill','chai_wan','tsim_sha_tsui','jordan','mong_kok','prince_edward','yau_ma_tei','kowloon_city','kowloon_bay','kwun_tong','lam_tin','san_po_kong','cheung_sha_wan','sham_shui_po','whampoa','hung_hom','kai_tak','to_kwa_wan','kwai_chung','tsuen_wan','sha_tin','fo_tan','tuen_mun','yuen_long','po_lam','tai_po','fanling','sheung_shui','tseung_kwan_o','ma_on_shan','tin_shui_wai','tung_chung','other'];
const district = validDistricts.includes(prop.district) ? prop.district : 'other';

const chunks = [];
const getPage = (offset) => { 
  for (const ps of data.pageSpans) 
    if (offset >= ps.start && offset < ps.end) return ps.pageNumber; 
  return 1; 
};

for (let i = 0; i < data.text.length; i += CHUNK_SIZE - OVERLAP) {
  const chunk = data.text.substring(i, i + CHUNK_SIZE);
  if (chunk.trim().length > 50) {
    chunks.push({ content: chunk, chunkType: 'text', pageNumber: getPage(i) });
  }
}

data.tables.forEach((t, i) => { 
  if (t.content?.trim().length > 20) 
    chunks.push({ content: `[Table ${i+1}]\n${t.content}`, chunkType: 'table', pageNumber: t.pageNumber }); 
});

data.figures.forEach((f, i) => { 
  if (f.caption?.trim().length > 10) 
    chunks.push({ content: `[Figure ${i+1}]: ${f.caption}`, chunkType: 'figure', pageNumber: f.pageNumber }); 
});

const embedResult = await this.helpers.httpRequest({ 
  method: 'POST', 
  url: `${config.AZURE_OPENAI_ENDPOINT}/openai/deployments/text-embedding-3-small/embeddings?api-version=2024-02-01`, 
  headers: { 'api-key': config.AZURE_OPENAI_KEY, 'Content-Type': 'application/json' }, 
  body: { input: chunks.map(c => c.content), dimensions: 1024 }, 
  json: true 
});
const embeddings = embedResult.data || [];

const stableHash = (s) => { 
  let h = 5381; 
  for (let i = 0; i < s.length; i++) h = ((h << 5) + h + s.charCodeAt(i)) >>> 0; 
  return h.toString(16).padStart(8, '0'); 
};
const fileHash = stableHash(data.fileName.toLowerCase());

const docs = chunks.map((chunk, idx) => ({
  '@search.action': 'upload',
  id: `${fileHash}_${idx}_${stableHash(chunk.content.slice(0, 100))}`,
  content: chunk.content,
  fileName: data.fileName,
  blobPath: data.blobPath,
  chunkIndex: idx,
  chunkType: chunk.chunkType,
  pageNumber: chunk.pageNumber,
  aiDocType: prop.docType || 'listing',
  aiLanguage: prop.language || '',
  aiConfidence: Number(prop.confidence || 0),
  aiKeyTopics: keyTopics,
  embedding: embeddings[idx]?.embedding || [],
  isImage: false,
  imageUrl: '',
  propertyName: prop.name || '',
  propertyNameCn: prop.name_cn || '',
  buildingName: prop.building_name || '',
  district: district,
  floor: prop.floor || '',
  unit: prop.unit || '',
  propertyType: prop.property_type || '',
  listingType: prop.listing_type || 'leasing',
  grossArea: prop.gross_area ? Number(prop.gross_area) : null,
  netArea: prop.net_area ? Number(prop.net_area) : null,
  askingRent: prop.asking_rent ? Number(prop.asking_rent) : null,
  rentPerSqft: prop.rent_per_sqft ? Number(prop.rent_per_sqft) : null,
  availableFrom: prop.available_from || ''
}));

const indexResult = await this.helpers.httpRequest({ 
  method: 'POST', 
  url: `${config.AZURE_SEARCH_ENDPOINT}/indexes/${config.AZURE_SEARCH_LISTING_INDEX}/docs/index?api-version=2023-11-01`, 
  headers: { 'api-key': config.AZURE_SEARCH_API_KEY, 'Content-Type': 'application/json' }, 
  body: { value: docs }, 
  json: true 
});

return { 
  json: { 
    fileName: data.fileName, 
    blobPath: data.blobPath,
    encodedBlobPath: data.encodedBlobPath,
    fileType: data.fileType,
    stats: data.stats, 
    propertyData: prop, 
    classification: 'listing',
    chunksIndexed: docs.length, 
    indexResult: indexResult.value?.length || 0, 
    indexName: config.AZURE_SEARCH_LISTING_INDEX,
    _config: config 
  } 
};

const data = $json;
const config = data._config;
const prop = data.propertyData || {};
const now = new Date();

const validDistricts = [
  'central', 'admiralty', 'wan_chai', 'causeway_bay', 'north_point',
  'quarry_bay', 'taikoo', 'wong_chuk_hang', 'sheung_wan', 'sai_ying_pun',
  'tsim_sha_tsui', 'jordan', 'mong_kok', 'kowloon_bay', 'kwun_tong', 'lam_tin',
  'san_po_kong', 'cheung_sha_wan', 'kwai_chung', 'tsuen_wan', 'sha_tin',
  'fo_tan', 'tuen_mun', 'yuen_long', 'tai_po', 'other'
];
const district = validDistricts.includes(prop.district) ? prop.district : 'other';
const listingType = prop.listing_type === 'coworking' ? 'coworking' : 'leasing';

let descEn = '<div>';
if (prop.gross_area) descEn += '<p><strong>Gross Area:</strong> ' + prop.gross_area + ' sq.ft.</p>';
if (prop.net_area) descEn += '<p><strong>Net Area:</strong> ' + prop.net_area + ' sq.ft.</p>';
if (prop.asking_rent_text) descEn += '<p><strong>Asking Rent:</strong> ' + prop.asking_rent_text + '</p>';
if (prop.management_fee_psf) descEn += '<p><strong>Management Fee:</strong> HK$' + prop.management_fee_psf + '/sq.ft.</p>';
if (prop.lease_terms) descEn += '<p><strong>Lease Terms:</strong> ' + prop.lease_terms + '</p>';
if (prop.handover_condition) descEn += '<p><strong>Handover:</strong> ' + prop.handover_condition + '</p>';
if (prop.description_en) descEn += '<p>' + prop.description_en + '</p>';
descEn += '<hr/><p><small>Source: ' + data.fileName + ' | Processed: ' + now.toISOString() + '</small></p></div>';

let descCn = '<div>';
if (prop.gross_area) descCn += '<p><strong>建築面積:</strong> ' + prop.gross_area + ' 平方尺</p>';
if (prop.net_area) descCn += '<p><strong>實用面積:</strong> ' + prop.net_area + ' 平方尺</p>';
if (prop.asking_rent_text) descCn += '<p><strong>租金:</strong> ' + prop.asking_rent_text + '</p>';
if (prop.description_cn) descCn += '<p>' + prop.description_cn + '</p>';
descCn += '</div>';

let odooResult = { success: false };
let uid = null;

try {
  const authResponse = await this.helpers.httpRequest({
    method: 'POST',
    url: config.ODOO_URL + '/jsonrpc',
    headers: { 'Content-Type': 'application/json' },
    body: {
      jsonrpc: '2.0',
      method: 'call',
      params: { service: 'common', method: 'authenticate', args: [config.ODOO_DB, config.ODOO_USERNAME, config.ODOO_API_KEY, {}] },
      id: 1
    },
    json: true
  });
  uid = authResponse.result;
  if (!uid) throw new Error('Odoo auth failed');

  const searchResponse = await this.helpers.httpRequest({
    method: 'POST',
    url: config.ODOO_URL + '/jsonrpc',
    headers: { 'Content-Type': 'application/json' },
    body: {
      jsonrpc: '2.0',
      method: 'call',
      params: {
        service: 'object',
        method: 'execute_kw',
        args: [config.ODOO_DB, uid, config.ODOO_API_KEY, 'c21.property.listing', 'search', [[["description", "ilike", "Source: " + data.fileName]]], { limit: 1 }]
      },
      id: 2
    },
    json: true
  });

  const existingId = (searchResponse.result || [])[0] || null;

  const listingData = {
    name: prop.name || data.fileName.replace(/\.(pdf|jpg|jpeg|png)$/i, '').replace(/_/g, ' '),
    listing_type: listingType,
    district: district,
    description: descEn,
    description_cn: descCn
  };

  if (prop.name_cn) listingData.name_cn = prop.name_cn;
  if (prop.building_name) listingData.building_name = prop.building_name;
  if (prop.address) listingData.address = prop.address;
  if (prop.floor) listingData.floor = prop.floor;
  if (prop.unit) listingData.unit = prop.unit;
  if (prop.gross_area) listingData.gross_area = Number(prop.gross_area);
  if (prop.net_area) listingData.net_area = Number(prop.net_area);
  if (prop.asking_rent) listingData.asking_rent = Number(prop.asking_rent);
  if (prop.lease_terms) listingData.lease_terms = prop.lease_terms;

  let listingId, refCode;

  if (existingId) {
    await this.helpers.httpRequest({
      method: 'POST',
      url: config.ODOO_URL + '/jsonrpc',
      headers: { 'Content-Type': 'application/json' },
      body: {
        jsonrpc: '2.0',
        method: 'call',
        params: { service: 'object', method: 'execute_kw', args: [config.ODOO_DB, uid, config.ODOO_API_KEY, 'c21.property.listing', 'write', [[existingId], listingData]] },
        id: 3
      },
      json: true
    });

    const existingImagesResponse = await this.helpers.httpRequest({
      method: 'POST',
      url: config.ODOO_URL + '/jsonrpc',
      headers: { 'Content-Type': 'application/json' },
      body: {
        jsonrpc: '2.0',
        method: 'call',
        params: {
          service: 'object',
          method: 'execute_kw',
          args: [config.ODOO_DB, uid, config.ODOO_API_KEY, 'c21.property.image', 'search', [[["property_id", "=", existingId]]]]
        },
        id: 5
      },
      json: true
    });
    const existingImageIds = existingImagesResponse.result || [];
    if (existingImageIds.length > 0) {
      await this.helpers.httpRequest({
        method: 'POST',
        url: config.ODOO_URL + '/jsonrpc',
        headers: { 'Content-Type': 'application/json' },
        body: {
          jsonrpc: '2.0',
          method: 'call',
          params: { service: 'object', method: 'execute_kw', args: [config.ODOO_DB, uid, config.ODOO_API_KEY, 'c21.property.image', 'unlink', [existingImageIds]] },
          id: 6
        },
        json: true
      });
    }

    listingId = existingId;
    odooResult = { success: true, listingId, uid, isUpdate: true, deletedImages: existingImageIds.length, model: 'c21.property.listing' };
  } else {
    refCode = 'PROP-' + now.getFullYear() + String(now.getMonth() + 1).padStart(2, '0') + String(now.getDate()).padStart(2, '0') + '-' + Date.now().toString(36).toUpperCase();
    listingData.ref_code = refCode;
    listingData.approval_status = 'draft';
    listingData.state = 'available';

    const createResponse = await this.helpers.httpRequest({
      method: 'POST',
      url: config.ODOO_URL + '/jsonrpc',
      headers: { 'Content-Type': 'application/json' },
      body: {
        jsonrpc: '2.0',
        method: 'call',
        params: { service: 'object', method: 'execute_kw', args: [config.ODOO_DB, uid, config.ODOO_API_KEY, 'c21.property.listing', 'create', [listingData]] },
        id: 4
      },
      json: true
    });

    if (createResponse.result) {
      listingId = createResponse.result;
      odooResult = { success: true, listingId, uid, refCode, isUpdate: false, model: 'c21.property.listing' };
    }
  }
} catch (e) {
  odooResult = { success: false, error: e.message, model: 'c21.property.listing' };
}

return {
  json: {
    fileName: data.fileName,
    blobPath: data.blobPath,
    encodedBlobPath: data.encodedBlobPath,
    fileType: data.fileType,
    stats: data.stats,
    propertyData: data.propertyData,
    classification: 'listing',
    chunksIndexed: data.chunksIndexed,
    indexResult: data.indexResult,
    indexName: data.indexName,
    odooResult,
    _config: config
  }
};

const data = $json;
const config = data._config;
const odooResult = data.odooResult || {};

let imageUploadResults = [];
let pdfCoResult = { success: false, pagesConverted: 0 };

if (!odooResult.success || !odooResult.listingId) {
  return { json: { ...data, odooResult: { ...odooResult, imagesUploaded: 0, imagesFailed: 0, imageDetails: [], pdfCoError: 'No listing ID' } } };
}

const uid = odooResult.uid;
const listingId = odooResult.listingId;

if (data.fileType === 'image') {
  try {
