const data = $json;
const config = data._config;
const news = data.newsData || {};
const CHUNK_SIZE = 600;
const OVERLAP = 150;

const keyTopics = [];
if (news.property_name) keyTopics.push(news.property_name);
if (news.property_name_cn) keyTopics.push(news.property_name_cn);
if (news.district) keyTopics.push(news.district);

const validDistricts = ['central','admiralty','wan_chai','causeway_bay','north_point','quarry_bay','taikoo','wong_chuk_hang','sheung_wan','tsim_sha_tsui','jordan','mong_kok','kowloon_bay','kwun_tong','san_po_kong','kwai_chung','tsuen_wan','sha_tin','fo_tan','tuen_mun','yuen_long','other'];
const district = validDistricts.includes(news.district) ? news.district : 'other';

const chunks = [];
const getPage = (offset) => { 
  for (const ps of data.pageSpans) 
    if (offset >= ps.start && offset < ps.end) return ps.pageNumber; 
  return 1; 
};

for (let i = 0; i < data.text.length; i += CHUNK_SIZE - OVERLAP) {
  const chunk = data.text.substring(i, i + CHUNK_SIZE);
  if (chunk.trim().length > 50) {
    chunks.push({ content: chunk, chunkType: 'text', pageNumber: getPage(i) });
  }
}

data.tables.forEach((t, i) => { 
  if (t.content?.trim().length > 20) 
    chunks.push({ content: `[Table ${i+1}]\n${t.content}`, chunkType: 'table', pageNumber: t.pageNumber }); 
});

const embedResult = await this.helpers.httpRequest({ 
  method: 'POST', 
  url: `${config.AZURE_OPENAI_ENDPOINT}/openai/deployments/text-embedding-3-small/embeddings?api-version=2024-02-01`, 
  headers: { 'api-key': config.AZURE_OPENAI_KEY, 'Content-Type': 'application/json' }, 
  body: { input: chunks.map(c => c.content), dimensions: 1024 }, 
  json: true 
});
const embeddings = embedResult.data || [];

const stableHash = (s) => { 
  let h = 5381; 
  for (let i = 0; i < s.length; i++) h = ((h << 5) + h + s.charCodeAt(i)) >>> 0; 
  return h.toString(16).padStart(8, '0'); 
};
const fileHash = stableHash(data.fileName.toLowerCase());

const docs = chunks.map((chunk, idx) => ({
  '@search.action': 'upload',
  id: `${fileHash}_${idx}_${stableHash(chunk.content.slice(0, 100))}`,
  content: chunk.content,
  fileName: data.fileName,
  blobPath: data.blobPath,
  chunkIndex: idx,
  chunkType: chunk.chunkType,
  pageNumber: chunk.pageNumber,
  embedding: embeddings[idx]?.embedding || [],
  articleType: news.articleType || 'other',
  headline: news.headline || '',
  headlineEn: news.headline_en || '',
  source: news.source || '',
  publishDate: news.publish_date || '',
  propertyName: news.property_name || '',
  propertyNameCn: news.property_name_cn || '',
  district: district,
  propertyType: news.property_type || '',
  transactionPrice: news.transaction_price ? Number(news.transaction_price) : null,
  grossArea: news.gross_area ? Number(news.gross_area) : null,
  seller: news.seller || '',
  buyer: news.buyer || '',
  marketSentiment: news.market_sentiment || 'neutral',
  summaryEn: news.summary_en || '',
  summaryCn: news.summary_cn || ''
}));

const indexResult = await this.helpers.httpRequest({ 
  method: 'POST', 
  url: `${config.AZURE_SEARCH_ENDPOINT}/indexes/${config.AZURE_SEARCH_NEWS_INDEX}/docs/index?api-version=2023-11-01`, 
  headers: { 'api-key': config.AZURE_SEARCH_API_KEY, 'Content-Type': 'application/json' }, 
  body: { value: docs }, 
  json: true 
});

return { 
  json: { 
    fileName: data.fileName, 
    blobPath: data.blobPath,
    encodedBlobPath: data.encodedBlobPath,
    fileType: data.fileType,
    stats: data.stats, 
    newsData: news, 
    classification: 'news',
    chunksIndexed: docs.length, 
    indexResult: indexResult.value?.length || 0, 
    indexName: config.AZURE_SEARCH_NEWS_INDEX,
    _config: config 
  } 
};

