  }
  description += '\n\n---\nSource: ' + data.fileName + ' | Processed: ' + now.toISOString();

  const newsRecord = {
    name: news.headline || news.headline_en || data.fileName.replace(/\.(pdf|jpg|jpeg|png)$/i, ''),
    description: description,
    source: news.source || 'Unknown',
    is_property_news: true,
    relevance_score: Math.round((news.confidence || 0.7) * 100)
