    existingId = (searchResponse.result || [])[0] || null;
    debugLog.push({ step: 'partner_search', searchDomain, found: !!existingId, existingId });
  }

  // Build notes with all contact info
  const notes = [];
  notes.push(`Source: ${data.fileName}`);
  notes.push(`Imported: ${now.toISOString()}`);
  if (contact.mobile) notes.push(`Mobile: ${contact.mobile}`);
  if (contact.phone && contact.mobile && contact.phone !== contact.mobile) notes.push(`Office: ${contact.phone}`);
  if (contact.department) notes.push(`Department: ${contact.department}`);
  if (contact.title_cn) notes.push(`Title (CN): ${contact.title_cn}`);
  if (contact.name_cn) notes.push(`Name (CN): ${contact.name_cn}`);

  const partnerData = {
    name: contact.name || 'Unknown Contact',
