  };

  if (companyId) partnerData.parent_id = companyId;
  if (contact.title) partnerData.function = contact.title;
  if (contact.email) partnerData.email = contact.email;
  // Use mobile as phone if no phone provided, otherwise use phone
  partnerData.phone = contact.mobile || contact.phone || '';
  if (contact.website) partnerData.website = contact.website;
  if (contact.address) partnerData.street = contact.address;
  if (contact.city) partnerData.city = contact.city;

  debugLog.push({ step: 'partnerData', partnerData });

  let partnerId;

  if (existingId) {
    const updateResponse = await this.helpers.httpRequest({
      method: 'POST',
      url: config.ODOO_URL + '/jsonrpc',
      headers: { 'Content-Type': 'application/json' },
