    });
    checkOdooResponse(updateResponse, 'partner_update');
    partnerId = existingId;
    odooResult = { success: true, partnerId, uid, companyId, isUpdate: true, model: 'res.partner' };
    debugLog.push({ step: 'partner_updated', partnerId });
  } else {
    const createResponse = await this.helpers.httpRequest({
      method: 'POST',
      url: config.ODOO_URL + '/jsonrpc',
      headers: { 'Content-Type': 'application/json' },
      body: {
        jsonrpc: '2.0',
        method: 'call',
        params: { service: 'object', method: 'execute_kw', args: [config.ODOO_DB, uid, config.ODOO_API_KEY, 'res.partner', 'create', [partnerData]] },
        id: 6
      },
      json: true
    });
    checkOdooResponse(createResponse, 'partner_create');

    if (createResponse.result) {
      partnerId = createResponse.result;
      odooResult = { success: true, partnerId, uid, companyId, isUpdate: false, model: 'res.partner' };
      debugLog.push({ step: 'partner_created', partnerId });
    } else {
      throw new Error('Partner create returned no result');
    }
  }
} catch (e) {
  debugLog.push({ step: 'error', message: e.message });
  odooResult = { success: false, error: e.message, model: 'res.partner', debugLog };
