};

// Function to detect district from address
function detectDistrict(address) {
  for (const [cn, key] of Object.entries(districtMap)) {
    if (address.includes(cn)) return key;
  }
  return 'other';
}

// Function to extract property ID
function extractPropertyId(text) {
  const match = text.match(/樓盤編號[：:]*\s*(\d+)/);
  return match ? match[1] : null;
}

// Function to parse rent amount
function parseRent(rentText) {
  if (!rentText) return null;
  const cleaned = String(rentText).replace(/[^\d]/g, '');
  return cleaned ? parseInt(cleaned) : null;
}

// Function to parse area
function parseArea(areaText) {
  if (!areaText) return null;
  const match = String(areaText).match(/([\d,]+)/);
  if (match) {
    return parseInt(match[1].replace(/,/g, ''));
  }
  return null;
}

// Parse tables to extract property listings
const properties = [];
let currentIndex = 0;

for (const table of data.tables) {
  const rows = table.content.split('\n');

  for (const row of rows) {
    // Skip header rows
    if (row.includes('物業地址') || row.includes('租客狀況') || row.includes('交吉情況')) {
      continue;
    }

    // Look for numbered entries like "1)" or "1." followed by address
    const numberedMatch = row.match(/^(\d+)[\)\.]\s*(.+)/);
    if (numberedMatch) {
      currentIndex++;
      const cols = row.split(' | ').map(c => c.trim());

      // Extract property ID from the row or nearby text
      const propertyId = extractPropertyId(row) || `LIST-${currentIndex}`;

      // First column typically contains address
      const addressPart = cols[0] || '';
      const district = detectDistrict(addressPart);

      // Look for area, rent in subsequent columns
      let area = null;
      let rent = null;
      let vacancy = 'unknown';
      let tenant = '';
      let doorWidth = null;

      for (const col of cols) {
        if (col.match(/Vacant|已吉|現吉|商議|隨吉/i)) {
          vacancy = col;
        }
        if (col.match(/\d{1,2}\.\d/) && !area) {
          // Likely door width (e.g., 12.0)
          doorWidth = parseFloat(col);
        }
        if (col.match(/\d{2,3},\d{3}/) || col.match(/^\d{4,6}$/)) {
          // Likely rent (e.g., 50,000 or 50000)
          const parsed = parseRent(col);
          if (parsed && parsed > 10000 && parsed < 10000000) {
            rent = parsed;
          }
        }
        if (col.match(/\d{3,4}\s*G?$/i)) {
          // Likely area (e.g., 1,800 G or 1800)
          const parsed = parseArea(col);
          if (parsed && parsed > 50 && parsed < 100000) {
            area = parsed;
          }
        }
        if (col.match(/\(前\)|餐|店|銀行|醫|茶|燒|粉|飯/)) {
          tenant = col;
        }
      }

      properties.push({
        index: currentIndex,
        propertyId,
        address: addressPart.replace(/^\d+[\)\.]\s*/, '').trim(),
        district,
        tenant,
        vacancy,
        grossArea: area,
        doorWidthFt: doorWidth,
        askingRent: rent,
        sourceFile: data.fileName,
        sourcePage: table.pageNumber
      });
    }
  }
}

// If no properties found via numbered parsing, try alternative parsing
if (properties.length === 0) {
  // Fallback: split by property ID pattern
  const propIdMatches = data.text.matchAll(/樓盤編號[：:]*\s*(\d+)/g);
  for (const match of propIdMatches) {
    currentIndex++;
    properties.push({
      index: currentIndex,
      propertyId: match[1],
      address: '',
      district: 'other',
      tenant: '',
      vacancy: '',
      grossArea: null,
      doorWidthFt: null,
      askingRent: null,
      sourceFile: data.fileName,
      sourcePage: 1,
      needsManualReview: true
    });
  }
}

return {
  json: {
    ...data,
    listItems: properties,
    listItemCount: properties.length,
    parsingMethod: properties.length > 0 ? 'table' : 'fallback'
  }
};

