  'cheung_sha_wan', 'sham_shui_po', 'whampoa', 'hung_hom', 'kai_tak', 'to_kwa_wan',
  'kwai_chung', 'tsuen_wan', 'sha_tin', 'fo_tan', 'tuen_mun', 'yuen_long',
  'po_lam', 'tai_po', 'fanling', 'sheung_shui', 'tseung_kwan_o',
  'ma_on_shan', 'tin_shui_wai', 'tung_chung', 'other'
];

const district = validDistricts.includes(prop.district) ? prop.district : 'other';

// Build content for embedding
const content = [
  prop.name || '',
  prop.name_cn || '',
  prop.address || '',
  prop.district || '',
  prop.gross_area ? `${prop.gross_area} sqft` : '',
  prop.asking_rent ? `HK$${prop.asking_rent}/month` : ''
].filter(Boolean).join(' | ');

// Generate stable hash for document ID
const stableHash = (s) => {
  let h = 5381;
  for (let i = 0; i < s.length; i++) h = ((h << 5) + h + s.charCodeAt(i)) >>> 0;
  return h.toString(16).padStart(8, '0');
};

const docId = `list_${stableHash(batchInfo.sourceFile)}_${batchInfo.currentIndex}`;

// Get embedding from Azure OpenAI
const embedResult = await this.helpers.httpRequest({
  method: 'POST',
  url: `${config.AZURE_OPENAI_ENDPOINT}/openai/deployments/text-embedding-3-small/embeddings?api-version=2024-02-01`,
  headers: { 'api-key': config.AZURE_OPENAI_KEY, 'Content-Type': 'application/json' },
  body: { input: [content], dimensions: 1024 },
  json: true
});

const embedding = embedResult.data?.[0]?.embedding || [];

// Build document for Azure Search
const doc = {
  '@search.action': 'upload',
  id: docId,
  content: content,
  fileName: batchInfo.sourceFile,
  blobPath: batchInfo.blobPath || '',
  chunkIndex: batchInfo.currentIndex - 1,
  chunkType: 'list_item',
  pageNumber: data.originalItem?.sourcePage || 1,
  aiDocType: 'listing_list',
  aiLanguage: 'mixed',
  aiConfidence: 0.8,
  aiKeyTopics: [prop.district, 'retail', 'leasing'].filter(Boolean),
  embedding: embedding,
  isImage: false,
  imageUrl: '',
  propertyName: prop.name || '',
  propertyNameCn: prop.name_cn || '',
  buildingName: '',
  district: district,
  floor: '',
  unit: '',
  propertyType: 'retail',
  listingType: 'leasing',
  grossArea: prop.gross_area ? Number(prop.gross_area) : null,
  netArea: null,
  askingRent: prop.asking_rent ? Number(prop.asking_rent) : null,
  rentPerSqft: null,
  availableFrom: ''
};

// Index to Azure Search
const indexResult = await this.helpers.httpRequest({
  method: 'POST',
  url: `${config.AZURE_SEARCH_ENDPOINT}/indexes/${config.AZURE_SEARCH_LISTING_INDEX}/docs/index?api-version=2023-11-01`,
  headers: { 'api-key': config.AZURE_SEARCH_API_KEY, 'Content-Type': 'application/json' },
  body: { value: [doc] },
  json: true
});

return {
  json: {
    ...data,
    indexResult: {
      indexed: true,
      docId: docId,
      indexName: config.AZURE_SEARCH_LISTING_INDEX
    }
  }
};
